{% set child_table_data = doc.items %}

{% set result_list = [] %}

{% for row in child_table_data %}
    {% set row_dict = {
        'item_name': row.item_name,
        'image': row.image,
        'barcode' : row.barcode,
        'description': row.description,
        'gst_hsn_code': row.gst_hsn_code,
        'qty': row.qty,
        'uom': row.uom,
        'curr': doc.price_list_currency,
        'rate': row.rate,
        'item_tax_rate': row.item_tax_template,
        'taxable_value': row.taxable_value,
        'amount': row.amount
   } %}
    {% set _ = result_list.append(row_dict) %}
{% endfor %}

{% set sorted_result_list = result_list | sort(attribute='item_code') %}

{% for row in sorted_result_list %}
    {% set _ = row.update({'idx': loop.index}) %}
{% endfor %}

{# ── Flag for hiding image column ── #}
{% set hide_image = doc.custom_hide_image %}

{# ── Flag for hiding item description ── #}
{% set hide_description = doc.custom_hide_item_description %}

{# ── Number of copies ── #}
{% set no_of_copy = doc.custom_no_of_copy %}
{% if no_of_copy == "Two" %}
    {% set copy_list = ["Original for Recipient", "Duplicate for Transporter"] %}
{% elif no_of_copy == "Three" %}
    {% set copy_list = ["Original for Recipient", "Duplicate for Transporter", "Triplicate for Supplier"] %}
{% else %}
    {% set copy_list = ["Original for Recipient"] %}
{% endif %}

{% for copy_label in copy_list %}
{% if not loop.first %}<div style="page-break-before:always;"></div>{% endif %}
<div style="text-align:right; font-weight:bold; font-size:11px; margin-bottom:2px; padding-right:4px;">
    {{ copy_label }}
</div>

{# ── Build HSN-wise quantity summary ── #}
{% set hsn_summary = {} %}
{% for item in sorted_result_list %}
    {% set hsn = item['gst_hsn_code'] %}
    {% if hsn not in hsn_summary %}
        {% set _ = hsn_summary.update({hsn: {'qty': 0}}) %}
    {% endif %}
    {% set entry = hsn_summary[hsn] %}
    {% set _ = hsn_summary.update({hsn: {'qty': entry['qty'] + item['qty']|int}}) %}
{% endfor %}

<style>
@media print {
  @page {
    size: A4;
    margin: 10mm 8mm 10mm 8mm !important;
  }
  body {
    font-family: "Arial", sans-serif;
    font-size: 9.5px;
    -webkit-print-color-adjust: exact !important;
    color-adjust: exact !important;
    line-height: 1.2;
  }
  table {
    border-collapse: collapse;
    width: 100%;
    table-layout: fixed;
    word-wrap: break-word;
  }
  th, td {
    padding: 2px 3px;
    word-break: break-word;
    vertical-align: top;
  }
  img {
    max-width: 100%;
  }
  .content-01, .content-02 {
    page-break-inside: avoid;
  }
}

table {
  border-collapse: collapse !important;
  width: 100% !important;
  table-layout: fixed !important;
  word-wrap: break-word !important;
}
th, td {
  font-size: 9px !important;
  word-break: break-word !important;
  white-space: normal !important;
  line-height: 1.2 !important;
  padding: 2px 4px !important;
}
.content-01 {
  font-size: 9.5px !important;
}
.tax-breakup-wrap table {
    width: 100% !important;
    table-layout: fixed !important;
    max-width: 100% !important;
    word-wrap: break-word !important;
    font-size: 9px !important;
}
.tax-breakup-wrap td, .tax-breakup-wrap th {
    white-space: normal !important;
    word-break: break-word !important;
    font-size: 9px !important;
    padding: 2px 3px !important;
}
.irn-table td, .irn-table th {
    padding: 3px 6px !important;
    vertical-align: middle !important;
    line-height: 1.3 !important;
    height: auto !important;
}
</style>

<div style="font-size:10px;" class="content-01">
    <table border="1" style="border-top: 8px inset black; border-bottom: 8px outset black; border-left: none; border-right: none;" width="100%">
        <tbody>
            <tr>
                <td style="border-right: 2px solid grey;" width="20%"><div style="padding-top: 5px; padding-left: 10px;"><img alt="logo" height="" src="/files/shree logo.jpg" style="height: 130px; width: 130px;"></div></td>
                <td style="border-right: 2px; border-bottom: 1px solid #cdd0d4;" width="50%">
                    <div style="display: inline;">
                        <br>
                        <div style="display: flex; align-items: center; font-family: cursive; font-size: 12px; font-weight: bold; gap: 10px;">
                            <img alt="M. D. Mohta" src="/files/Name.png" style="height: 25px; width: 150px; padding-left: 50px; filter: grayscale(100%);">
                            <u>Rakhi Pvt. Ltd.</u>
                        </div>
                        <p style="padding-left: 50px; font-size: 10px;">P- 31A Kalakar Street, 3rd Floor, Kolkata - 700007 <br>Phone 2270 1893/94, M.9331150473 <br>WAREHOUSE : 89/1, Salkia School Road, Howrah-711106 <br>Phone : 2665-4107 E-mail : shreerakhi@gmail.com <br>GSTIN : 19AAECM5102C1ZY CIN NO - U74999WB2005PTC104002</p>
                    </div>
                </td>
                <td style="border-left: 0px; border-bottom: 1px solid #cdd0d4;" width="30%">
                    <div style="height:140px; display:table; width:100%;">
                        <div style="display:table-cell; vertical-align:middle; text-align:right; padding-right:15px;">
                            {%- if doc.is_return -%}
                                <span style="font-size:20px; font-weight:bold; white-space:nowrap;">Credit Note</span>
                            {%- else -%}
                                {%- if doc.meta.is_submittable and doc.docstatus==0 -%}
                                    <span style="font-size:20px; font-weight:bold; white-space:nowrap;">Proforma Invoice</span>
                                {%- else -%}
                                    {%- if doc.irn -%}
                                        <span style="font-size:20px; font-weight:bold; white-space:nowrap;">Tax Invoice</span>
                                    {%- else -%}
                                        <span style="font-size:20px; font-weight:bold; white-space:nowrap;">Bill of Supply</span>
                                    {%- endif -%}
                                    {%- if doc.docstatus==2 -%}
                                        <br><span style="font-size:20px; font-weight:bold; white-space:nowrap;">Cancelled</span>
                                    {%- endif -%}
                                {%- endif -%}
                            {%- endif -%}
                        </div>
                    </div>
                </td>
            </tr>
        </tbody>
    </table>
</div>

<table width="100%" class="table table-bordered">
    <tr>
        <th style="border-right: 0px;" width="15%">
            {%- if doc.is_return -%}
            Credit Note No.<br>
            Credit Note Date<br>
            Return Against<br>
            {%- else -%}
            Invoice No.<br>
            Invoice Date<br>
            {%- endif -%}
            Terms<br>
            Due Date<br>
            {%- if doc.ewaybill -%} E-Way Bill No {%- endif -%}
        </th>
        <td style="border-left: 0px;" width="35%">
            {{doc.name}}<br>
            {{doc.get_formatted('posting_date')}}<br>
            {%- if doc.is_return -%}{{doc.return_against}}<br>{%- endif -%}
            {{doc.payment_terms_template}}<br>
            {{doc.get_formatted('due_date')}}<br>
            {%- if doc.ewaybill -%} {{doc.ewaybill}} {%- endif -%}
        </td>
        <th style="border-right: 0px;" width="25%">
            {%- if doc.is_return -%}
                Remarks
            {%- else -%}
                Place of Supply <br>
                {%- if doc.po_no -%}P.O. No <br>{%- endif -%}
                {%- if doc.po_date -%}P.O. Date <br>{%- endif -%}
                {%- if not doc.irn -%} Product Description <br>{%- endif -%}
                {%- if doc.custom_bos_transporter -%}Transporter<br>{%- endif -%}
                {%- if doc.custom_number_of_carton -%}Total Packages {%- endif -%}
            {%- endif -%}
        </th>
        <td style="border-left: 0px;" width="25%">
            {%- if doc.is_return -%}
                {{doc.remarks}}
            {%- else -%}
                {{doc.place_of_supply}}<br>
                {%- if doc.po_no -%}{{doc.po_no}}<br>{%- endif -%}
                {%- if doc.po_date -%}{{doc.get_formatted('po_date')}}<br>{%- endif -%}
                {%- if not doc.irn -%} <b>RAKHI - EXEMPTED</b><br> {%- endif -%}
                {%- if doc.custom_bos_transporter -%}{{ doc.custom_bos_transporter }}<br> {%- endif -%}
                {%- if doc.custom_number_of_carton -%}{{ doc.custom_number_of_carton }}<br> {%- endif -%}
            {%- endif -%}
        </td>
    </tr>
    <tr><td colspan="4" align="right"> Page No. 1 </td></tr>
</table>

<table width="100%" class="table table-bordered" style="margin-top:-20px">
    <tr>
        <th width="50%" bgcolor="Lavender">Bill To</th>
        <th width="50%" bgcolor="Lavender">Ship To</th>
    </tr>
    <tr>
        <td width="50%">{{doc.customer_name}}<br>{{ doc.address_display }}</td>
        {% if doc.shipping_address_name and doc.shipping_address %}
            <td width="50%">{{doc.custom_shipping_address_title}}<br>{{ doc.shipping_address }}<br></td>
        {% else %}
            <td width="50%">{{doc.customer_name}}<br>{{ doc.address_display }}</td>
        {% endif %}
    </tr>
</table>

{#
    Column widths:
    WITH image  : # 4% | Image 15% | Item 18% | HSN 10% | Qty 10% | Rate 8% | GST% 8% | GST Amt 11% | Amount 16%  → total cols = 9
    WITHOUT image: # 4% | Item 33%  | HSN 10%  | Qty 10% | Rate 8% | GST% 8% | GST Amt 11% | Amount 16%            → total cols = 8
#}
<table width="100%" class="table table-bordered" border="1" style="margin-top:-21px">
    <tr>
        <th width="4%"  rowspan="2" align="center">#</th>
        {% if not hide_image %}
        <th width="15%" rowspan="2" align="left">Image</th>
        {% endif %}
        <th width="{{ '18%' if not hide_image else '33%' }}" rowspan="2" align="left">{% if hide_description %}Item{% else %}Item &amp; Description{% endif %}</th>
        <th width="10%" rowspan="2" align="center">HSN/SAC</th>
        <th width="10%" rowspan="2" align="center">Quantity</th>
        <th width="8%"  rowspan="2" align="center"><center>Rate</center></th>
        <th width="19%" colspan="2" align="center"><center>GST</center></th>
        <th width="16%" rowspan="2" align="center"><center>Amount</center></th>
    </tr>
    <tr>
        <th width="8%"  align="center"><center>%</center></th>
        <th width="11%" align="center"><center>Amount</center></th>
    </tr>

    {% set vars = {'total_box':0.0, 'total_amount': 0.0, 'last_idx':0} %}
    {% set item_len = sorted_result_list|length %}
    {% for item in sorted_result_list %}
        {% if item['idx'] <= 10 %}
            <tr>
                <td width="4%" align="center">{{ item['idx'] }} &nbsp;</td>
                {% if not hide_image %}
                <td width="15%" align="center">
                    {% if item['image'] %}
                        <img src="{{ item['image'] }}" style="height:60px; width:60px;">
                    {% else %}
                        No Image
                    {% endif %}
                </td>
                {% endif %}
                <td width="{{ '18%' if not hide_image else '33%' }}" align="left">{{ item['item_name'] }}{% if not hide_description %} <br> {{ item['description'] }}{% endif %}</td>
                <td width="10%" align="center">{{ item['gst_hsn_code'] }}</td>
                <td width="10%" align="right">{{ item['qty']|int }} &nbsp; {{ item['uom'] }}</td>
                <td width="8%"  align="right">{{ frappe.format_value(item['rate'], {'fieldtype': 'Currency', 'options': 'INR'}, doc)}}</td>
                {% if item['item_tax_rate'] %}
                    {% set list1 = item['item_tax_rate'].split(' ') %}
                    {% set temp = list1[1] %}
                    {% set rate = temp[:-1]|float %}
                    <td width="8%"  align="right">{{ rate }} % </td>
                    {% set taxed_amt = item['taxable_value'] * (rate/100) %}
                    <td width="11%" align="right">{{ frappe.format_value(taxed_amt, {'fieldtype': 'Currency', 'options': 'INR'}, doc) }} </td>
                    <td width="16%" align="right">{{ frappe.format_value(item['amount'], {'fieldtype': 'Currency', 'options': 'INR'}, doc) }} </td>
                {% else %}
                    <td width="8%"  align="right"> 0 % </td>
                    <td width="11%" align="right">{{ frappe.format_value(item['taxable_value'], {'fieldtype': 'Currency', 'options': 'INR'}, doc) }} </td>
                    <td width="16%" align="right">{{ frappe.format_value(item['amount'], {'fieldtype': 'Currency', 'options': 'INR'}, doc) }} </td>
                {% endif %}
                {% set vars = vars.update({'total_box': vars.total_box + item['qty']|int, 'total_amount': vars.total_amount + item['amount']|float, 'last_idx': vars.last_idx + 1}) %}
            </tr>
        {%- endif -%}
    {%- endfor -%}

    {% if item_len > 10 %}
    <tr>
        <td colspan="{{ '9' if not hide_image else '8' }}"><br></td>
    </tr>
    <tr>
        <td></td>
        {% if not hide_image %}<td></td>{% endif %}
        <td></td>
        <td></td>
        <td align="right" style="font-weight:bold;">{{ vars.total_box|int }}</td>
        <td align="right"></td>
        <td align="center"></td>
        <td align="right"></td>
        <td align="right" style="font-weight:bold;">{{ frappe.format_value(vars.total_amount, {'fieldtype': 'Currency', 'options': 'INR'}, doc) }} </td>
    </tr>
    {% endif %}

    {% if vars.last_idx == item_len %}
        <tr><td colspan="{{ '9' if not hide_image else '8' }}"><br></td></tr>
        <tr>
            <td colspan="{{ '4' if not hide_image else '3' }}" style="border-right:0;" align="left"><b><i>AMOUNT</i></b></td>
            <td style="border-left:0;" align="right"><b>{{ vars.total_box|int }}</b></td>
            <td colspan="3"></td>
            <td align="right"><b>{{ frappe.format_value(vars.total_amount, {'fieldtype': 'Currency', 'options': 'INR'}, doc) }}</b></td>
        </tr>
        {% if doc.discount_amount > 0 %}
            <tr>
                <td colspan="{{ '7' if not hide_image else '6' }}">DISCOUNT (Less : )</td>
                <td align="right">{{ "%0.2f" | format(doc.additional_discount_percentage|float) }}%</td>
                <td align="right">{{ frappe.format_value(doc.discount_amount, {'fieldtype': 'Currency', 'options': 'INR'}, doc) }}</td>
            </tr>
        {% endif %}
        {% for row in doc.taxes %}
            <tr>
                {% if row.description != 'Freight and Forwarding Charges' %}
                    <td colspan="{{ '8' if not hide_image else '7' }}">{{ row.description }}</td>
                    <td align="right">{{ frappe.format_value(row.tax_amount, {'fieldtype': 'Currency', 'options': 'INR'}, doc) }} </td>
                {% else %}
                    <td colspan="{{ '4' if not hide_image else '3' }}" style="border-right:0;">{{ row.description }}</td>
                    <td colspan="2" style="border-left:0; border-right-color:transparent;">No. of cases</td>
                    <td align="right" style="border-left:0;">{{ "%0.2f" | format(doc.custom_number_of_carton|float) }}</td>
                    <td align="right">{{ frappe.format_value(doc.custom_rate_per_carton, {'fieldtype': 'Currency', 'options': 'INR'}, doc) }} </td>
                    <td align="right">{{ frappe.format_value(row.tax_amount, {'fieldtype': 'Currency', 'options': 'INR'}, doc) }} </td>
                {% endif %}
            </tr>
        {% endfor %}
        <tr>
            <td colspan="{{ '8' if not hide_image else '7' }}" style="font-weight:bold"><i>ROUNDING ADJUSTMENT</i></td>
            <td align="right"><b>{{ frappe.format_value(doc.rounding_adjustment, {'fieldtype': 'Currency', 'options': 'INR'}, doc) }}</b></td>
        </tr>
        <tr>
            <td colspan="{{ '8' if not hide_image else '7' }}" style="font-weight:bold"><i>TOTAL AMOUNT</i></td>
            <td align="right"><b>{{ frappe.format_value(doc.rounded_total, {'fieldtype': 'Currency', 'options': 'INR'}, doc) }}</b></td>
        </tr>
        <tr>
            <td colspan="{{ '9' if not hide_image else '8' }}"><i>Rs. {{ doc.in_words[4:] }}</i></td>
        </tr>
        <tr>
            <td colspan="{{ '9' if not hide_image else '8' }}" style="text-align:right; vertical-align:center">
                <div style="font-family: cursive; font-size: 10px; font-weight: bold;"><b>For</b><img alt="M.D.MOHTA" src="/files/Name.png" style="height: 15px; width: 100px; filter: grayscale(100%)"><u>Rakhi Pvt. Ltd.</u></div><br>
                <div style="font-family: cursive; font-size: 10px; font-weight: bold;"><img alt="" src="/files/kks_sig-removebg-preview.png" style="height: 30px; width: 200px; filter: grayscale(100%)"></div><br>
                <b>Director &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</b>
            </td>
        </tr>
    </table>

    {# ── Tax Breakup Page 1 ── #}
    <div style="border:1px solid black; font-size:9px; margin-top:-21px;">
        <div style="padding:2px 4px; font-weight:bold; border-bottom:1px solid black;"><b>Tax Breakup</b></div>
        <div class="tax-breakup-wrap">
            {{ doc.other_charges_calculation }}
        </div>
        <div style="padding:3px 6px; border-top:1px solid #999; font-size:9px;">
            <b>HSN-wise Qty : </b>
            {% for hsn, data in hsn_summary.items() %}
                <span style="margin-right:14px;">&#9658; {{ hsn }} : <b>{{ data['qty'] }}</b></span>
            {% endfor %}
        </div>
    </div><br><br>

    {% endif %}

    {% if vars.last_idx == item_len and doc.irn %}
        <table width="100%" class="table table-bordered irn-table" border="1" style="margin-top:-21px; border-collapse:collapse;">
            <tr>
                <td rowspan="4" width="25%" style="text-align:center; padding:4px; vertical-align:middle;">
                    {% if doc.irn %}
                        {% set e_invoice_log = frappe.db.get_value("e-Invoice Log", doc.irn, ("invoice_data", "signed_qr_code"), as_dict=True) %}
                        {%- set invoice_data = dict(json.loads(e_invoice_log.invoice_data)) -%}
                        <img src="data:image/png;base64,{{ get_qr_code(e_invoice_log.signed_qr_code, scale=2) }}" class="qrcode" style="height:90px; width:90px; display:block; margin:0 auto;">
                    {% endif %}
                </td>
                <th width="15%" style="text-align:left; padding:3px 6px; vertical-align:middle;">IRN</th>
                <td width="60%" style="text-align:left; padding:3px 6px; vertical-align:middle; word-break:break-all; font-size:8px;">{{ doc.irn }}</td>
            </tr>
            {% set e_invoice_log = frappe.db.get_value("e-Invoice Log", doc.irn, ("invoice_data"), as_dict=True) %}
            {%- set invoice_data = _dict(json.loads(e_invoice_log.invoice_data)) -%}
            {%
                set transaction_details = {
                    "Ack. No": invoice_data.AckNo,
                    "Ack. Date": frappe.utils.format_datetime(invoice_data.AckDt, "dd/MM/yyyy hh:mm:ss"),
                }
            %}
            {% for key, value in transaction_details.items() %}
                <tr>
                    <th width="15%" style="text-align:left; padding:3px 6px; vertical-align:middle;">{{ key }}</th>
                    <td width="60%" style="text-align:left; padding:3px 6px; vertical-align:middle;">{{ value }}</td>
                </tr>
            {% endfor %}
            <tr>
                <td colspan="2" style="text-align:center; padding:3px 6px; font-weight:bold; font-size:8px;">e-Invoicing detail(s) generated from the Goverment's e-Invoicing Sysyem.</td>
            </tr>
        </table>
    {% endif %}

    {% if vars.last_idx == item_len and not doc.irn %}
        <table width="100%" style="margin-top:-21px; font-weight:bold">
            <tr>
                <td>
                    <p>Please pay in favour of "M.D.MOHTA RAKHI PVT.LTD." Through either</p>
                    <p>ICICI Bank Ltd.,Kolkata A/c No 694905600912 IFSC Code ICIC0006949 </p>
                    <p>Rakhi is exempted from GST vide Notification No.19/2018 Dated 26/07/18</p>
                </td>
                <td style="text-align:center;">Authorised Signatory</td>
            </tr>
            <tr>
                <td><p>Amendment No.02/2017 Dated 28/06/2017</p></td>
                <td style="text-align:center;">E.& O.E.</td>
            </tr>
        </table>
    {% endif %}


{% if item_len > 10 %}
    <div style="font-size:12px;" class="content-02">
        {% set total_page = (item_len - 10)/20 %}
        {% if total_page|int == total_page|float %}
            {% set total_page = total_page|int + 0 %}
        {% else %}
            {% set total_page = total_page|int + 1 %}
        {% endif %}
        {% for i in range(1, total_page|int + 1) %}
            <table width="100%" class="table table-bordered" style="page-break-before: always;">
                <tr>
                    <td colspan="2" align="center">
                        {%- if doc.is_return -%}
                            <b>Credit Note</b>
                        {%- else -%}
                            {%- if doc.meta.is_submittable and doc.docstatus==0-%}
                                <b>Proforma Invoice</b>
                            {%- else -%}
                                {%- if doc.irn -%}
                                    <b>Tax Invoice</b>
                                {%- else -%}
                                    <b>Bill of Supply</b>
                                {%- endif -%}
                                {%- if doc.docstatus==2 -%}
                                    <br><b>Cancelled</b>
                                {%- endif -%}
                            {%- endif -%}
                        {%- endif -%}
                    </td>
                </tr>
                <tr>
                    <td width="50%">
                        {%- if doc.is_return -%}
                            CREDIT NOTE NO. : {{doc.name}}&emsp;&emsp;&emsp;&emsp;&emsp;DATE : {{doc.get_formatted('posting_date')}}<br>
                            RETURN AGAINST : {{doc.return_against}}&emsp;&emsp;REMARKS : {{doc.remarks}}
                        {%- else -%}
                            INVOICE NO. : {{doc.name}}&emsp;&emsp;&emsp;&emsp;&emsp;DATE : {{doc.get_formatted('posting_date')}}
                        {%- endif -%}
                    </td>
                    <td width="50%"><b>State Code & Name :</b>&emsp;{{doc.place_of_supply}}&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Page No : {{ i + 1 }}</td>
                </tr>
            </table>

            <table width="100%" class="table table-bordered" border="1" style="margin-top:-21px">
                <tr>
                    <th width="4%"  rowspan="2" align="center">#</th>
                    {% if not hide_image %}
                    <th width="15%" rowspan="2" align="left">Image</th>
                    {% endif %}
                    <th width="{{ '18%' if not hide_image else '33%' }}" rowspan="2" align="left">{% if hide_description %}Item{% else %}Item &amp; Description{% endif %}</th>
                    <th width="10%" rowspan="2" align="center">HSN/SAC</th>
                    <th width="10%" rowspan="2" align="center">Quantity</th>
                    <th width="8%"  rowspan="2" align="center"><center>Rate</center></th>
                    <th width="19%" colspan="2" align="center"><center>GST</center></th>
                    <th width="16%" rowspan="2" align="center"><center>Amount</center></th>
                </tr>
                <tr>
                    <th width="8%"  align="center"><center>%</center></th>
                    <th width="11%" align="center"><center>Amount</center></th>
                </tr>
                <tr><td colspan="{{ '9' if not hide_image else '8' }}"><br></td></tr>
                <tr>
                    <td></td>
                    {% if not hide_image %}<td></td>{% endif %}
                    <td></td>
                    <td></td>
                    <td align="right" style="font-weight:bold;">{{ vars.total_box|int }}</td>
                    <td align="right"></td>
                    <td align="center"></td>
                    <td align="right"></td>
                    <td align="right" style="font-weight:bold;">{{ frappe.format_value(vars.total_amount, {'fieldtype': 'Currency', 'options': 'INR'}, doc) }}</td>
                </tr>
                {% set vars1 = {'last_idx_1': vars.last_idx + 20} %}
                {% for item in sorted_result_list %}
                    {% if item['idx'] > vars.last_idx and item['idx'] <= vars1.last_idx_1 %}
                        <tr>
                            <td width="4%" align="center">{{ item['idx'] }}</td>
                            {% if not hide_image %}
                            <td width="15%" align="center">
                                {% if item['image'] %}
                                    <img src="{{ item['image'] }}" style="height:60px; width:60px;">
                                {% else %}
                                    No Image
                                {% endif %}
                            </td>
                            {% endif %}
                            <td width="{{ '18%' if not hide_image else '33%' }}" align="left">{{ item['item_name'] }}{% if not hide_description %} <br> {{ item['description'] }}{% endif %}</td>
                            <td width="10%" align="center">{{ item['gst_hsn_code'] }}</td>
                            <td width="10%" align="right">{{ item['qty']|int }} &nbsp; {{ item['uom'] }}</td>
                            <td width="8%"  align="right">{{ frappe.format_value(item['rate'], {'fieldtype': 'Currency', 'options': 'INR'}, doc) }} </td>
                            {% if item['item_tax_rate'] %}
                                {% set list1 = item['item_tax_rate'].split(' ') %}
                                {% set temp = list1[1] %}
                                {% set rate = temp[:-1]|float %}
                                <td width="8%"  align="right">{{ rate }} % </td>
                                {% set taxed_amt = item['taxable_value'] * (rate/100) %}
                                <td width="11%" align="right"> {{ frappe.format_value(taxed_amt, {'fieldtype': 'Currency', 'options': 'INR'}, doc) }} </td>
                                <td width="16%" align="right"> {{ frappe.format_value(item['amount'], {'fieldtype': 'Currency', 'options': 'INR'}, doc) }} </td>
                            {% else %}
                                <td width="8%"  align="right"> 0 % </td>
                                <td width="11%" align="right"> {{ frappe.format_value(item['taxable_value'], {'fieldtype': 'Currency', 'options': 'INR'}, doc) }} </td>
                                <td width="16%" align="right"> {{ frappe.format_value(item['amount'], {'fieldtype': 'Currency', 'options': 'INR'}, doc) }} </td>
                            {% endif %}
                            {% set vars = vars.update({'total_box': vars.total_box + item['qty']|int, 'total_amount': vars.total_amount + item['amount']|float, 'last_idx': vars.last_idx + 1}) %}
                        </tr>
                    {% endif %}
                {% endfor %}

                {% if vars.last_idx != item_len %}
                    <tr><td colspan="{{ '9' if not hide_image else '8' }}"><br></td></tr>
                    <tr>
                        <td></td>
                        {% if not hide_image %}<td></td>{% endif %}
                        <td></td>
                        <td></td>
                        <td align="right" style="font-weight:bold;">{{ vars.total_box|int }}</td>
                        <td align="right"></td>
                        <td align="center"></td>
                        <td align="right"></td>
                        <td align="right" style="font-weight:bold;">{{ frappe.format_value(vars.total_amount, {'fieldtype': 'Currency', 'options': 'INR'}, doc) }} </td>
                    </tr>
                {% endif %}

                {% if vars.last_idx == item_len %}
                    <tr><td colspan="{{ '9' if not hide_image else '8' }}"><br></td></tr>
                    <tr>
                        <td colspan="{{ '4' if not hide_image else '3' }}" style="border-right:0;" align="left"><b><i>AMOUNT</i></b></td>
                        <td style="border-left:0;" align="right"><b>{{ vars.total_box|int }}</b></td>
                        <td colspan="3"></td>
                        <td align="right"><b>{{ frappe.format_value(vars.total_amount, {'fieldtype': 'Currency', 'options': 'INR'}, doc) }}</b></td>
                    </tr>
                    {% if doc.discount_amount > 0 %}
                        <tr>
                            <td colspan="{{ '7' if not hide_image else '6' }}">DISCOUNT (Less : )</td>
                            <td align="right">{{ "%0.2f" | format(doc.additional_discount_percentage|float) }}%</td>
                            <td align="right">{{ frappe.format_value(doc.discount_amount, {'fieldtype': 'Currency', 'options': 'INR'}, doc) }}</td>
                        </tr>
                    {% endif %}
                    {% for row in doc.taxes %}
                        <tr>
                            {% if row.description != 'Freight and Forwarding Charges' %}
                                <td colspan="{{ '8' if not hide_image else '7' }}">{{ row.description }}</td>
                                <td align="right">{{ frappe.format_value(row.tax_amount, {'fieldtype': 'Currency', 'options': 'INR'}, doc) }}</td>
                            {% else %}
                                <td colspan="{{ '4' if not hide_image else '3' }}" style="border-right:0;">{{ row.description }}</td>
                                <td colspan="2" style="border-left:0; border-right-color:transparent;">No. of cases</td>
                                <td align="right" style="border-left:0;">{{ "%0.2f" | format(doc.custom_number_of_carton|float) }}</td>
                                <td align="right">{{ frappe.format_value(doc.custom_rate_per_carton, {'fieldtype': 'Currency', 'options': 'INR'}, doc) }}</td>
                                <td align="right">{{ frappe.format_value(row.tax_amount, {'fieldtype': 'Currency', 'options': 'INR'}, doc) }}</td>
                            {% endif %}
                        </tr>
                    {% endfor %}
                    <tr>
                        <td colspan="{{ '8' if not hide_image else '7' }}" style="font-weight:bold"><i>ROUNDING ADJUSTMENT</i></td>
                        <td align="right"><b>{{ frappe.format_value(doc.rounding_adjustment, {'fieldtype': 'Currency', 'options': 'INR'}, doc) }}</b></td>
                    </tr>
                    <tr>
                        <td colspan="{{ '8' if not hide_image else '7' }}" style="font-weight:bold"><i>TOTAL AMOUNT</i></td>
                        <td align="right"><b>{{ frappe.format_value(doc.rounded_total, {'fieldtype': 'Currency', 'options': 'INR'}, doc) }}</b></td>
                    </tr>
                    <tr>
                        <td colspan="{{ '9' if not hide_image else '8' }}"><i>Rs. {{ doc.in_words[4:] }}</i></td>
                    </tr>
                    <tr>
                        <td colspan="{{ '9' if not hide_image else '8' }}" style="text-align:right; vertical-align:center">
                            <div style="font-family: cursive; font-size: 10px; font-weight: bold;"><b>For</b><img alt="M.D.MOHTA" src="/files/Name.png" style="height: 15px; width: 100px; filter: grayscale(100%)"><u>Rakhi Pvt. Ltd.</u></div><br>
                            <div style="font-family: cursive; font-size: 10px; font-weight: bold;"><img alt="" src="/files/kks_sig-removebg-preview.png" style="height: 30px; width: 200px; filter: grayscale(100%)"></div><br>
                            <b>Director &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</b>
                        </td>
                    </tr>
                </table>

                {# ── Tax Breakup Subsequent Pages ── #}
                <div style="border:1px solid black; font-size:9px; margin-top:-21px;">
                    <div style="padding:2px 4px; font-weight:bold; border-bottom:1px solid black;"><b>Tax Breakup</b></div>
                    <div class="tax-breakup-wrap">
                        {{ doc.other_charges_calculation }}
                    </div>
                    <div style="padding:3px 6px; border-top:1px solid #999; font-size:9px;">
                        <b>HSN-wise Qty : </b>
                        {% for hsn, data in hsn_summary.items() %}
                            <span style="margin-right:14px;">&#9658; {{ hsn }} : <b>{{ data['qty'] }}</b></span>
                        {% endfor %}
                    </div>
                </div><br><br>

                {% endif %}
                </table>

            {% if vars.last_idx == item_len and doc.irn %}
                <table width="100%" class="table table-bordered irn-table" border="1" style="margin-top:-21px; border-collapse:collapse;">
                    <tr>
                        <td rowspan="4" width="25%" style="text-align:center; padding:4px; vertical-align:middle;">
                            {% if doc.irn %}
                                {% set e_invoice_log = frappe.db.get_value("e-Invoice Log", doc.irn, ("invoice_data", "signed_qr_code"), as_dict=True) %}
                                {%- set invoice_data = dict(json.loads(e_invoice_log.invoice_data)) -%}
                                <img src="data:image/png;base64,{{ get_qr_code(e_invoice_log.signed_qr_code, scale=2) }}" class="qrcode" style="height:90px; width:90px; display:block; margin:0 auto;">
                            {% endif %}
                        </td>
                        <th width="15%" style="text-align:left; padding:3px 6px; vertical-align:middle;">IRN</th>
                        <td width="60%" style="text-align:left; padding:3px 6px; vertical-align:middle; word-break:break-all; font-size:8px;">{{ doc.irn }}</td>
                    </tr>
                    {% set e_invoice_log = frappe.db.get_value("e-Invoice Log", doc.irn, ("invoice_data"), as_dict=True) %}
                    {%- set invoice_data = _dict(json.loads(e_invoice_log.invoice_data)) -%}
                    {%
                        set transaction_details = {
                            "Ack. No": invoice_data.AckNo,
                            "Ack. Date": frappe.utils.format_datetime(invoice_data.AckDt, "dd/MM/yyyy hh:mm:ss"),
                        }
                    %}
                    {% for key, value in transaction_details.items() %}
                        <tr>
                            <th width="15%" style="text-align:left; padding:3px 6px; vertical-align:middle;">{{ key }}</th>
                            <td width="60%" style="text-align:left; padding:3px 6px; vertical-align:middle;">{{ value }}</td>
                        </tr>
                    {% endfor %}
                    <tr>
                        <td colspan="2" style="text-align:center; padding:3px 6px; font-weight:bold; font-size:8px;">e-Invoicing detail(s) generated from the Goverment's e-Invoicing Sysyem.</td>
                    </tr>
                </table>
            {% endif %}

            {% if vars.last_idx == item_len and not doc.irn %}
                <table width="100%" style="margin-top:-21px; font-weight:bold">
                    <tr>
                        <td>
                            <p>Please pay in favour of "M.D.MOHTA RAKHI PVT.LTD." Through either</p>
                            <p>ICICI Bank Ltd.,Kolkata A/c No 694905600912 IFSC Code ICIC0006949 </p>
                            <p>Rakhi is exempted from GST vide Notification No.19/2018 Dated 26/07/18</p>
                        </td>
                        <td style="text-align:center;">Authorised Signatory</td>
                    </tr>
                    <tr>
                        <td><p>Amendment No.02/2017 Dated 28/06/2017</p></td>
                        <td style="text-align:center;">E.& O.E.</td>
                    </tr>
                </table>
            {% endif %}
        {% endfor %}
    </div>
{% endif %}

{# ── End of copy loop ── #}
{% endfor %}

{# ══════════════════════════════════════════════════════════════
   E-WAYBILL SECTION — prints on a new page if ewaybill exists
   ══════════════════════════════════════════════════════════════ #}
{% if doc.ewaybill %}
{%- set ewb_log = frappe.db.get_value("e-Waybill Log", doc.ewaybill, "data", as_dict=True) -%}
{% if ewb_log and ewb_log.data %}
{%- set ewb = _dict(json.loads(ewb_log.data)) -%}

{% if ewb.supplyType == "O" %}
    {% set ewb_generated_by = ewb.fromTrdName %}
{% else %}
    {% set ewb_generated_by = ewb.toTrdName %}
{% endif %}

<div style="page-break-before: always;"></div>

<style>
.ewb-wrap {
    font-family: Arial, sans-serif;
    font-size: 10px;
    line-height: 1.4;
    color: #000;
}
.ewb-wrap h1 {
    font-size: 20px;
    font-weight: bold;
    margin: 6px 0;
}
.ewb-wrap table {
    border-collapse: collapse;
    width: 100%;
    margin-bottom: 6px;
}
.ewb-wrap table.bordered td,
.ewb-wrap table.bordered th {
    border: 1px solid #999;
    padding: 3px 6px;
    vertical-align: top;
}
.ewb-wrap table.borderless td {
    border: none;
    padding: 2px 4px;
}
.ewb-wrap .bold { font-weight: bold; }
.ewb-wrap .text-center { text-align: center; }
.ewb-wrap .section-title {
    font-weight: bold;
    font-size: 11px;
    margin: 6px 0 2px 0;
}
.ewb-wrap .label-col { width: 200px; }
.ewb-wrap .qr-code { height: 120px; width: 120px; }
.ewb-wrap .barcode { max-width: 260px; height: 60px; }
</style>

<div class="ewb-wrap">

    <table class="borderless">
        <tbody>
            <tr>
                <td colspan="2" class="text-center">
                    <h1>e-Waybill</h1>
                </td>
            </tr>
            <tr>
                <td colspan="2" class="text-center">
                    <img src="data:image/png;base64,{{ get_e_waybill_qr_code(ewb.ewbNo, ewb.userGstin, ewb.ewayBillDate) }}" class="qr-code" />
                </td>
            </tr>
        </tbody>
    </table>

    {# ── e-Waybill header details ── #}
    <table class="bordered">
        <tbody>
            <tr>
                <td class="label-col">e-Waybill No</td>
                <td class="bold">{{ add_spacing(ewb.ewbNo, 4) }}</td>
            </tr>
            <tr>
                <td>e-Waybill Date</td>
                <td class="bold">{{ ewb.ewayBillDate | replace("00 ", "") }}</td>
            </tr>
            <tr>
                <td>Generated By</td>
                <td class="bold">{{ add_spacing(ewb.userGstin, 5) }} - {{ ewb_generated_by }}</td>
            </tr>
            <tr>
                <td>Valid From</td>
                <td class="bold">{{ ewb.ewayBillDate | replace(":00 ", " ") }} [{{ ewb.actualDist }} Kms]</td>
            </tr>
            <tr>
                <td>Valid Until</td>
                <td class="bold">{{ ewb.validUpto[:10] }}</td>
            </tr>
            {% if doc.irn %}
            <tr>
                <td>IRN</td>
                <td class="bold" style="word-break:break-all; font-size:8px;">{{ doc.irn }}</td>
            </tr>
            {% endif %}
        </tbody>
    </table>

    {# ── Part A ── #}
    <div class="section-title">Part - A</div>
    <table class="bordered">
        <tbody>
            <tr>
                <td class="label-col">GSTIN of Supplier</td>
                <td class="bold">{{ add_spacing(ewb.fromGstin, 5) }} - {{ ewb.fromTrdName }}</td>
            </tr>
            <tr>
                <td>Place of Dispatch</td>
                <td class="bold">{{ ewb.fromPlace }}, {{ get_state(ewb.actFromStateCode) }} - {{ ewb.fromPincode }}</td>
            </tr>
            <tr>
                <td>GSTIN of Recipient</td>
                <td class="bold">{{ add_spacing(ewb.toGstin, 5) }} - {{ ewb.toTrdName }}</td>
            </tr>
            <tr>
                <td>Place of Delivery</td>
                <td class="bold">{{ ewb.toPlace }}, {{ get_state(ewb.actToStateCode) }} - {{ ewb.toPincode }}</td>
            </tr>
            <tr>
                <td>Document No.</td>
                <td class="bold">{{ ewb.docNo }}</td>
            </tr>
            <tr>
                <td>Document Date</td>
                <td class="bold">{{ ewb.docDate }}</td>
            </tr>
            <tr>
                <td>Transaction Type</td>
                <td class="bold">{{ get_transport_type(ewb.transactionType) }}</td>
            </tr>
            <tr>
                <td>Value of Goods</td>
                <td class="bold">{{ frappe.utils.fmt_money(ewb.totInvValue, currency="INR") }}</td>
            </tr>
            <tr>
                <td>HSN Code</td>
                <td class="bold">
                    {{ ewb.itemList[0].hsnCode }}
                    {%- if ewb.itemList[0].productDesc %} - {{ ewb.itemList[0].productDesc }}{%- endif %}
                </td>
            </tr>
            <tr>
                <td>Reason for Transportation</td>
                <td class="bold">{{ get_supply_type(ewb.supplyType) }} - {{ get_sub_supply_type(ewb.subSupplyType) }}</td>
            </tr>
            <tr>
                <td>Transporter</td>
                <td class="bold">{{ add_spacing(ewb.transporterId, 5) }} - {{ ewb.transporterName }}</td>
            </tr>
        </tbody>
    </table>

    {# ── Part B ── #}
    {% if ewb.VehiclListDetails and ewb.VehiclListDetails|length > 0 %}
    <div class="section-title">Part - B</div>
    <table class="bordered">
        <tbody>
            <tr class="bold">
                <td>Mode</td>
                <td>Vehicle / Trans Doc No &amp; Dt.</td>
                <td>From</td>
                <td>Entered Date</td>
                <td>Entered By</td>
                <td>Cdata No. (If any)</td>
                <td>Multi Veh. Info (If any)</td>
            </tr>
            {% for detail in ewb.VehiclListDetails %}
            <tr>
                <td>{{ get_transport_mode(detail.transMode) }}</td>
                <td>
                    {{ detail.vehicleNo }}
                    {% if detail.transDocNo %} / {{ detail.transDocNo }}{% endif %}
                    {% if detail.transDocDate %} - Dt {{ detail.transDocDate }}{% endif %}
                </td>
                <td>{{ detail.fromPlace }}</td>
                <td>{{ detail.enteredDate | replace(":00 ", " ") }}</td>
                <td>{{ detail.userGSTINTransin }}</td>
                <td>-</td>
                <td>-</td>
            </tr>
            {% endfor %}
        </tbody>
    </table>
    {% endif %}

    {# ── Barcode ── #}
    <div style="text-align:center; margin-top:8px;">
        <img class="barcode" src="data:image/png;base64,{{ get_ewaybill_barcode(ewb.ewbNo) }}">
    </div>

</div>
{% endif %}
{% endif %}
